module multi_pipe_8bit (
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output reg mul_en_out,
    output reg [15:0] mul_out
);

reg [1:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
wire [15:0] temp [7:0];
wire [15:0] sum [3:0];
reg [15:0] mul_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out_reg <= 2'b00;
    end else begin
        mul_en_out_reg <= {mul_en_out_reg[0], mul_en_in};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'h00;
        mul_b_reg <= 8'h00;
    end else if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end

assign temp[0] = mul_a_reg * mul_b_reg[0];
assign temp[1] = mul_a_reg * mul_b_reg[1];
assign temp[2] = mul_a_reg * mul_b_reg[2];
assign temp[3] = mul_a_reg * mul_b_reg[3];
assign temp[4] = mul_a_reg * mul_b_reg[4];
assign temp[5] = mul_a_reg * mul_b_reg[5];
assign temp[6] = mul_a_reg * mul_b_reg[6];
assign temp[7] = mul_a_reg * mul_b_reg[7];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        sum[0] <= 16'h0000;
        sum[1] <= 16'h0000;
        sum[2] <= 16'h0000;
        sum[3] <= 16'h0000;
    end else begin
        sum[0] <= {8'b0, temp[0]};
        sum[1] <= sum[0] + {7'b0, temp[1]};
        sum[2] <= sum[1] + {6'b0, temp[2]};
        sum[3] <= sum[2] + {5'b0, temp[3]};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out_reg <= 16'h0000;
    end else begin
        mul_out_reg <= sum[3] + {4'b0, temp[4]} + {3'b0, temp[5]} + {2'b0, temp[6]} + {1'b0, temp[7]};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 16'h0000;
    end else if (mul_en_out_reg[1]) begin
        mul_out <= mul_out_reg;
    end else begin
        mul_out <= 16'h0000;
    end
end

assign mul_en_out = mul_en_out_reg[1];

endmodule
